def GetLSProData(page_data,Cookie_Jar,m,url = ''):
    from resources.lib.modules import client,control
    import re,requests
    from datetime import datetime, timedelta
    if not control.infoLabel('Container.PluginName') == 'plugin.video.thecrew': return
    urls = [
        'https://roxiestreams.info/march-madness',
        'https://roxiestreams.su/march-madness'
    ]
    page_data = ''
    for u in urls:
        try:
            page_data = requests.get(u, timeout=3).text
            if page_data and '<a href=' in page_data:
                break
        except:
            continue
    r = re.findall(r'(?s)<a href="([^"]+)">\s*([^<]+)</a>.*?<td>\s*([^<]+)</td>', page_data)
    out = []
    for link, name, timestr in r:
        try:
            dt = datetime.strptime(timestr.strip(), "%B %d, %Y %I:%M %p")
            dt = dt + timedelta(hours=3)
            timestr = dt.strftime("%I:%M %p")
        except:
            pass
        out.append((link, name.strip(), timestr.strip()))
    return out
